import "../styles/WhyChooseUs.css";

export default function WhyChooseUs() {
  return (
    <section className="why-us-section">
      <div className="why-us-logo">
        {/* Replace with your logo or icon */}
        <img src="/path-to-your-logo/logo.svg" alt="Why Choose Us" />
      </div>
      <h3>Why Choose Us</h3>
      <ul>
        <li>Creative & Custom Design</li>
        <li>Fast & Scalable Code</li>
        <li>Transparent Communication</li>
        <li>Experienced Team of Professionals</li>
        <li>Quality & Performance Focused</li>
        <li>Customer-Centric Approach</li>
      </ul>
      <div className="why-us-decoration"></div>
    </section>
  );
}
